    it('creates cache entries for all variants when they do not exist', () => {
      const shots = [createShot('shot-1'), createShot('shot-2')];
      updateAllShotsCaches(queryClient, projectId, () => shots);

      // When no existing cache, it creates at the list(projectId, 0) key
      const variant0 = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 0));
      expect(variant0).toEqual(shots);
    });

    it('updates existing cache entries', () => {
      const initialShots = [createShot('shot-1')];
      // Pre-populate one cache variant
      queryClient.setQueryData(queryKeys.shots.list(projectId, 0), initialShots);

      const updatedShots = [createShot('shot-1'), createShot('shot-2')];
      updateAllShotsCaches(queryClient, projectId, () => updatedShots);

      const result = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 0));
      expect(result).toEqual(updatedShots);
    });

    it('respects onlyExisting flag', () => {
      // Only populate one variant
      const initialShots = [createShot('shot-1')];
      queryClient.setQueryData(queryKeys.shots.list(projectId, 0), initialShots);

      const updatedShots = [createShot('shot-1'), createShot('shot-2')];
      updateAllShotsCaches(queryClient, projectId, () => updatedShots, true);

      // The populated variant should be updated
      const populatedResult = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 0));
      expect(populatedResult).toEqual(updatedShots);

      // Unpopulated variants should remain undefined
      const unpopulatedResult = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 2));
      expect(unpopulatedResult).toBeUndefined();
    });

    it('passes old data to updater function', () => {
      const initialShots = [createShot('shot-1')];
      queryClient.setQueryData(queryKeys.shots.list(projectId, 0), initialShots);

      updateAllShotsCaches(queryClient, projectId, (old) => {
        return [...(old || []), createShot('shot-2')];
      });

      const result = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 0));
      expect(result).toHaveLength(2);
      expect(result![0].id).toBe('shot-1');
      expect(result![1].id).toBe('shot-2');
    });
  });

  // ============================================================================
  // rollbackShotsCaches
  // ============================================================================

  describe('rollbackShotsCaches', () => {
    it('restores all cache variants to previous state', () => {
      const previousShots = [createShot('shot-1')];
      const currentShots = [createShot('shot-1'), createShot('shot-2')];

      // Set current state
      updateAllShotsCaches(queryClient, projectId, () => currentShots);

      // Rollback
      rollbackShotsCaches(queryClient, projectId, previousShots);

      const result = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 0));
      expect(result).toEqual(previousShots);
    });

    it('does nothing when previous is undefined', () => {
      const currentShots = [createShot('shot-1')];
      queryClient.setQueryData(queryKeys.shots.list(projectId, 0), currentShots);

      rollbackShotsCaches(queryClient, projectId, undefined);

      // Should not change
      const result = queryClient.getQueryData<Shot[]>(queryKeys.shots.list(projectId, 0));
      expect(result).toEqual(currentShots);
    });
  });

  // ============================================================================
  // findShotsCache
  // ============================================================================

  describe('findShotsCache', () => {
    it('returns the first non-empty cache', () => {
      const shots = [createShot('shot-1')];
      // Only populate one variant
      queryClient.setQueryData(queryKeys.shots.list(projectId, 2), shots);

      const result = findShotsCache(queryClient, projectId);
      expect(result).toEqual(shots);
    });

    it('returns undefined when no cache has data', () => {
      const result = findShotsCache(queryClient, projectId);
      expect(result).toBeUndefined();
    });

    it('skips empty arrays', () => {
      queryClient.setQueryData([...queryKeys.shots.all, projectId], []);
      const shots = [createShot('shot-1')];
      queryClient.setQueryData(queryKeys.shots.list(projectId, 0), shots);

      const result = findShotsCache(queryClient, projectId);
      expect(result).toEqual(shots);
    });
  });

  // ============================================================================
  // cancelShotsQueries
  // ============================================================================

  describe('cancelShotsQueries', () => {
    it('does not throw', async () => {
      await expect(cancelShotsQueries(queryClient, projectId)).resolves.not.toThrow();
    });
  });

  // ============================================================================
  // rollbackShotGenerationsCache
  // ============================================================================

  describe('rollbackShotGenerationsCache', () => {
    const shotId = 'shot-1';

    it('restores shot-generations cache to previous state', () => {
      const previous = [createGenerationRow('sg-1', 0), createGenerationRow('sg-2', 50)];
      const current = [createGenerationRow('sg-1', 0)]; // missing sg-2

      queryClient.setQueryData(queryKeys.generations.byShot(shotId), current);
      rollbackShotGenerationsCache(queryClient, shotId, previous);

      const result = queryClient.getQueryData<GenerationRow[]>(queryKeys.generations.byShot(shotId));
      expect(result).toEqual(previous);
    });

    it('does nothing when previous is undefined', () => {
      const current = [createGenerationRow('sg-1', 0)];
      queryClient.setQueryData(queryKeys.generations.byShot(shotId), current);

      rollbackShotGenerationsCache(queryClient, shotId, undefined);

      const result = queryClient.getQueryData<GenerationRow[]>(queryKeys.generations.byShot(shotId));
      expect(result).toEqual(current);
    });
  });

  // ============================================================================
  // cancelShotGenerationsQuery
  // ============================================================================

  describe('cancelShotGenerationsQuery', () => {
    it('does not throw', async () => {
      await expect(cancelShotGenerationsQuery(queryClient, 'shot-1')).resolves.not.toThrow();
    });
  });
});

import type { ShotCreationResult } from './shotCreationTypes';
import type {
  CreateEmptyShotPathInput,
  CreateShotWithFilesPathInput,
  CreateShotWithGenerationPathInput,
  CreateShotWithGenerationsPathInput,
} from './shotCreationTypes';
import { applyAtomicShotCacheUpdate } from './shotCacheUpdate';
import { enqueueGenerationsInvalidation } from '@/shared/hooks/invalidation/useGenerationInvalidation';
import { invalidateShotsQueries } from '@/shared/hooks/shots/cacheUtils';
import { insertAutoPositionedShotGeneration } from '@/shared/hooks/shots/addImageToShotHelpers';

export async function createShotWithGenerationPath(
  input: CreateShotWithGenerationPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    generationId,
    generationPreview,
    shots,
    queryClient,
    createShotWithImage,
  } = input;

  const rpcResult = await createShotWithImage({
    projectId: selectedProjectId,
    shotName,
    generationId,
  });

  applyAtomicShotCacheUpdate({
    selectedProjectId,
    shotId: rpcResult.shotId,
    shotName: rpcResult.shotName || shotName,
    shotGenerationId: rpcResult.shotGenerationId,
    generationId,
    generationPreview,
    shots,
    queryClient,
  });

  return {
    shotId: rpcResult.shotId,
    shotName: rpcResult.shotName,
    generationIds: [generationId],
  };
}

export async function createShotWithFilesPath(
  input: CreateShotWithFilesPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    files,
    aspectRatio,
    shots,
    onProgress,
    createShot,
    uploadToShot,
  } = input;

  const created = await createShot({
    name: shotName,
    projectId: selectedProjectId,
    aspectRatio: aspectRatio || undefined,
    shouldSelectAfterCreation: false,
  });

  const newShotId = created?.shot?.id;
  if (!newShotId) {
    throw new Error('Shot creation failed - no ID returned');
  }

  const uploadResult = await uploadToShot({
    imageFiles: files,
    targetShotId: newShotId,
    currentProjectQueryKey: selectedProjectId,
    currentShotCount: shots?.length ?? 0,
    onProgress,
  });

  if (!uploadResult?.shotId) {
    throw new Error('File upload failed - no images processed');
  }

  return {
    shotId: newShotId,
    shotName: created.shot?.name || shotName,
    shot: created.shot,
    generationIds: uploadResult.generationIds,
  };
}

export async function createShotWithGenerationsPath(
  input: CreateShotWithGenerationsPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    generationIds,
    queryClient,
    createShot,
  } = input;

  const createResult = await createShot({
    name: shotName,
    projectId: selectedProjectId,
    shouldSelectAfterCreation: false,
  });

  if (!createResult?.shot?.id) {
    throw new Error('Shot creation failed - no ID returned');
  }

  const shotId = createResult.shot.id;
  console.log('[ShotCreate:path] createShotWithGenerationsPath', {
    shotId,
    shotName,
    generationIds,
  });
  // The add_generation_to_shot RPC computes timeline_frame from
  // MAX(shot_generations.timeline_frame) + 50 without row-level locking, so
  // parallel calls can race and assign duplicate positions. Keep insertion serial.
  for (const generationId of generationIds) {
    const rpcResult = await insertAutoPositionedShotGeneration(shotId, generationId);
    console.log('[ShotCreate:path] insertAutoPositioned result', {
      generationId,
      rpcResult,
    });
  }

  // Invalidate generation queries immediately so shot-detail views pick up the
  // new images. Don't invalidate the shots LIST here — useCreateShot.onSuccess
  // already added the shot optimistically (with images: []).
  enqueueGenerationsInvalidation(queryClient, shotId, {
    reason: 'create-shot-with-generations',
    scope: 'all',
    includeShots: false,
    projectId: selectedProjectId,
    includeProjectUnified: true,
  });

  // Delayed shots-list invalidation: gives the DB time to commit the
  // shot_generations rows, then refetches the full list (with images).
  // The optimistic entry (images: []) is replaced with the real data.
  setTimeout(() => {
    invalidateShotsQueries(queryClient, selectedProjectId);
  }, 1500);

  return {
    shotId,
    shotName: createResult.shot.name || shotName,
    shot: createResult.shot,
    generationIds,
  };
}

export async function createEmptyShotPath(
  input: CreateEmptyShotPathInput,
): Promise<ShotCreationResult> {
  const { selectedProjectId, shotName, aspectRatio, createShot } = input;

  const createResult = await createShot({
    name: shotName,
    projectId: selectedProjectId,
    aspectRatio: aspectRatio || undefined,
    shouldSelectAfterCreation: false,
  });

  if (!createResult?.shot?.id) {
    throw new Error('Shot creation failed - no ID returned');
  }

  return {
    shotId: createResult.shot.id,
    shotName: createResult.shot.name || shotName,
    shot: createResult.shot,
  };
}

