import { useCallback } from 'react';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import type {
  CreateShotActionInput,
  CreateShotOptions,
  ShotCreationResult,
  UseShotCreationReturn,
} from './shotCreationTypes';
import {
  clearShotSkeletonEvent,
  dispatchShotSkeletonEvent,
} from './shotCreationEffects';
import {
  createEmptyShotPath,
  createShotWithFilesPath,
  createShotWithGenerationPath,
  createShotWithGenerationsPath,
} from './shotCreationPaths';

export function useCreateShotAction({
  selectedProjectId,
  shots,
  queryClient,
  setIsCreating,
  generateShotName,
  applyPostCreationEffects,
  createShotMutation,
  createShotWithImageMutation,
  handleExternalImageDropMutation,
}: CreateShotActionInput): UseShotCreationReturn['createShot'] {
  return useCallback(async (options: CreateShotOptions = {}): Promise<ShotCreationResult | null> => {
    if (!selectedProjectId) {
      toast.error('No project selected');
      return null;
    }

    const {
      name,
      generationId,
      generationIds,
      generationPreview,
      files,
      aspectRatio,
      dispatchSkeletonEvents = true,
      onProgress,
    } = options;

    const shotName = name || generateShotName();
    const imageCount = files?.length || generationIds?.length || (generationId ? 1 : 0);
    if (dispatchSkeletonEvents && imageCount > 0) {
      dispatchShotSkeletonEvent(imageCount);
    }

    setIsCreating(true);
    try {
      let result: ShotCreationResult;
      if (generationIds?.length && !files?.length) {
        result = await createShotWithGenerationsPath({
          selectedProjectId,
          shotName,
          generationIds,
          shots,
          queryClient,
          createShot: createShotMutation,
        });
      } else if (generationId && !files?.length) {
        result = await createShotWithGenerationPath({
          selectedProjectId,
          shotName,
          generationId,
          generationPreview,
          shots,
          queryClient,
          createShotWithImage: createShotWithImageMutation,
        });
      } else if (files?.length) {
        result = await createShotWithFilesPath({
          selectedProjectId,
          shotName,
          files,
          aspectRatio,
          shots,
          onProgress,
          createShot: createShotMutation,
          uploadToShot: handleExternalImageDropMutation,
        });
      } else {
        result = await createEmptyShotPath({
          selectedProjectId,
          shotName,
          aspectRatio,
          createShot: createShotMutation,
        });
      }

      applyPostCreationEffects(result, options);
      options.onSuccess?.(result);
      return result;
    } catch (error) {
      if (dispatchSkeletonEvents) {
        clearShotSkeletonEvent();
      }
      normalizeAndPresentError(error, {
        context: 'useShotCreation',
        toastTitle: 'Failed to create shot',
      });
      return null;
    } finally {
      setIsCreating(false);
    }
  }, [
    selectedProjectId,
    generateShotName,
    setIsCreating,
    createShotWithImageMutation,
    shots,
    queryClient,
    createShotMutation,
    handleExternalImageDropMutation,
    applyPostCreationEffects,
  ]);
}

/**
 * Unified Shot Creation Hook
 */

import { useState, useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useProject } from '@/shared/contexts/ProjectContext';
import { useLastAffectedShot } from '@/shared/hooks/shots/useLastAffectedShot';
import {
  useCreateShot,
  useCreateShotWithImage,
  useHandleExternalImageDrop,
} from '@/shared/hooks/shots';
import { useShots } from '@/shared/contexts/ShotsContext';
import { applyShotCreationPostEffects } from './shotCreationEffects';
import { useCreateShotAction } from './shotCreationAction';
import type {
  CreateShotOptions,
  ShotCreationResult,
  UseShotCreationReturn,
} from './shotCreationTypes';

export function useShotCreation(): UseShotCreationReturn {
  const { selectedProjectId } = useProject();
  const { shots } = useShots();
  const { setLastAffectedShotId } = useLastAffectedShot();
  const queryClient = useQueryClient();

  const createShotMutation = useCreateShot();
  const createShotWithImageMutation = useCreateShotWithImage();
  const handleExternalImageDropMutation = useHandleExternalImageDrop();

  const [isCreating, setIsCreating] = useState(false);
  const [lastCreatedShot, setLastCreatedShot] = useState<{ id: string; name: string } | null>(null);

  const clearLastCreated = useCallback(() => {
    setLastCreatedShot(null);
  }, []);

  const generateShotName = useCallback(() => {
    const count = shots?.length ?? 0;
    return `Shot ${count + 1}`;
  }, [shots]);

  const applyPostCreationEffects = useCallback((result: ShotCreationResult, options: CreateShotOptions) => {
    applyShotCreationPostEffects({
      result,
      options,
      selectedProjectId,
      shots,
      setLastAffectedShotId,
      setLastCreatedShot,
    });
  }, [selectedProjectId, shots, setLastAffectedShotId]);

  const createShot = useCreateShotAction({
    selectedProjectId,
    shots,
    queryClient,
    setIsCreating,
    generateShotName,
    applyPostCreationEffects,
    createShotMutation: createShotMutation.mutateAsync,
    createShotWithImageMutation: createShotWithImageMutation.mutateAsync,
    handleExternalImageDropMutation: handleExternalImageDropMutation.mutateAsync,
  });

  return {
    createShot,
    isCreating,
    lastCreatedShot,
    clearLastCreated,
  };
}

